	public unsafe struct MaDeviceIdPtr : IEquatable<MaDeviceIdPtr>
	{
		public MaDeviceIdPtr(MaDeviceId* handle) { Handle = handle; }

		public MaDeviceId* Handle;

		public bool IsNull => Handle == null;

		public static MaDeviceIdPtr Null => new MaDeviceIdPtr(null);

		public MaDeviceId this[int index] { get => Handle[index]; set => Handle[index] = value; }

		public static implicit operator MaDeviceIdPtr(MaDeviceId* handle) => new MaDeviceIdPtr(handle);

		public static implicit operator MaDeviceId*(MaDeviceIdPtr handle) => handle.Handle;

		public static bool operator ==(MaDeviceIdPtr left, MaDeviceIdPtr right) => left.Handle == right.Handle;

		public static bool operator !=(MaDeviceIdPtr left, MaDeviceIdPtr right) => left.Handle != right.Handle;

		public static bool operator ==(MaDeviceIdPtr left, MaDeviceId* right) => left.Handle == right;

		public static bool operator !=(MaDeviceIdPtr left, MaDeviceId* right) => left.Handle != right;

		public bool Equals(MaDeviceIdPtr other) => Handle == other.Handle;

		/// <inheritdoc/>
		public override bool Equals(object obj) => obj is MaDeviceIdPtr handle && Equals(handle);

		/// <inheritdoc/>
		public override int GetHashCode() => ((nuint)Handle).GetHashCode();

